#include<bits/stdc++.h>
using namespace std;
int cnt[16000],x[41000],n,m,ans[76000][4];
int main(void){
	cin>>n>>m;
	for(int i=1;i<=m;i++)cin>>x[i],cnt[x[i]]++;
	for(int t=1;9*t<=n;t++){
	    int res=0,a,b,c,d;
    	for(a=n-9*t-1;a>0;a--){
    		b=a+2*t;c=a+8*t+1;d=a+9*t+1;
    		res+=cnt[c]*cnt[d];ans[a][0]+=cnt[b]*res;
    		ans[b][1]+=cnt[a]*res;
    	}
    	res=0;
    	for(d=9*t+2;d<=n;d++){
    		a=d-9*t-1;b=d-7*t-1;c=d-t;
    		res+=cnt[a]*cnt[b];
    		ans[c][2]+=cnt[d]*res;
	    	ans[d][3]+=cnt[c]*res;
    	}
	}
	for(int i=1;i<=m;i++){
		for(int j=0;j<4;j++)cout<<ans[x[i]][j]<<' ';
		puts("");
	}
	return false;
}
